#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        while (Q--) {
            int Li, Ri, Ki;
            scanf("%d %d %d", &Li, &Ri, &Ki);
            int count = 0;
            for (int i = Li - 1; i < Ri; i++) {
                int j = i;
                while (j + 1 < Ri && A[j] == A[j + 1]) {
                    j++;
                }
                if (j - i + 1 >= Ki) {
                    count++;
                }
                i = j;
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

