code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Q = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            while (Q-- > 0) {
                int Li = sc.nextInt();
                int Ri = sc.nextInt();
                int Ki = sc.nextInt();
                int count = 0;
                for (int i = Li - 1; i < Ri; i++) {
                    int j = i;
                    while (j + 1 < Ri && A[j] == A[j + 1]) {
                        j++;
                    }
                    if (j - i + 1 >= Ki) {
                        count++;
                    }
                    i = j;
                }
                System.out.println(count);
            }
        }
    }
}

